#include <numeric>

#include <bits/stdc++.h>
using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(NULL) {}
};

class Solution {
public:
    ListNode* sortList(ListNode* head) {
        ListNode* zero = new ListNode(0);
        ListNode* one = new ListNode(0);
        ListNode* two = new ListNode(0);
        ListNode* z = zero;
        ListNode* o = one;
        ListNode* t = two;

        while (head) {
            if (head->val == 0) {
                z->next = head;
                z = z->next;
            } else if (head->val == 1) {
                o->next = head;
                o = o->next;
            } else {
                t->next = head;
                t = t->next;
            }
            head = head->next;
        }

        o->next = two->next;
        t->next = NULL;
        z->next = one->next;
        return zero->next;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> node_values(n);
    for (int i = 0; i < n; i++) cin >> node_values[i];

    ListNode* head = new ListNode(node_values[0]);
    ListNode* current = head;
    for (int i = 1; i < n; i++) {
        current->next = new ListNode(node_values[i]);
        current = current->next;
    }

    Solution sol;
    ListNode* sorted_head = sol.sortList(head);
    while (sorted_head) {
        cout << sorted_head->val << ' ';
        sorted_head = sorted_head->next;
    }
    cout << endl;
    return 0;
}
